function onloadRecaptcha2Callback(){document.querySelectorAll(".g-recaptcha").forEach(function(e){const t=grecaptcha.render(e,{sitekey:e.dataset.sitekey});e.dataset.widgetId=t;const a=e.closest("form");a&&a.addEventListener("marsFormSubmitFinished",function(a){a.detail.form.contains(e)&&grecaptcha.reset(t)})})}
